package com.example.documentviewer;

import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.provider.OpenableColumns;
import android.webkit.MimeTypeMap;
import android.widget.ImageView;
import android.widget.ScrollView;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;
import androidx.core.content.ContextCompat;

public class DocumentOpenActivity extends AppCompatActivity {

    public static final String EXTRA_DOCUMENT_URI = "extra_document_uri";

    private ImageView imageView;
    private TextView textView;
    private Uri documentUri;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        ScrollView root = new ScrollView(this);
        root.setFillViewport(true);

        imageView = new ImageView(this);
        imageView.setAdjustViewBounds(true);
        imageView.setScaleType(ImageView.ScaleType.FIT_CENTER);
        imageView.setVisibility(ImageView.GONE);

        textView = new TextView(this);
        textView.setTextSize(16f);
        textView.setTextColor(ContextCompat.getColor(this, android.R.color.black));

        root.addView(imageView);
        root.addView(textView);

        setContentView(root);

        handleIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleIntent(intent);
    }

    private void handleIntent(Intent intent) {
        if (intent == null) {
            showError("No document intent received");
            return;
        }

        Uri uri = intent.getData();
        if (uri == null) {
            String extra = intent.getStringExtra(EXTRA_DOCUMENT_URI);
            if (extra != null) {
                uri = Uri.parse(extra);
            }
        }

        if (uri == null) {
            showError("No document URI found");
            return;
        }

        documentUri = uri;

        String mimeType = getContentResolver().getType(uri);
        if (mimeType == null) {
            mimeType = guessMimeType(uri);
        }

        if (mimeType != null && mimeType.startsWith("image/")) {
            displayImage(uri);
        } else if ("application/pdf".equalsIgnoreCase(mimeType)) {
            displayPdf(uri);
        } else {
            displayGeneric(uri, mimeType);
        }
    }

    private void displayImage(Uri uri) {
        imageView.setVisibility(ImageView.VISIBLE);
        textView.setText("Image document:\n" + uri.toString());
        imageView.setImageURI(uri);
    }

    private void displayPdf(Uri uri) {
        imageView.setVisibility(ImageView.GONE);
        textView.setText("PDF document:\n" + uri.toString() + "\n\nOpen this URI in your PDF rendering component.");
    }

    private void displayGeneric(Uri uri, @Nullable String mimeType) {
        imageView.setVisibility(ImageView.GONE);
        textView.setText("Document:\n" + uri.toString() + "\nMIME: " + (mimeType != null ? mimeType : "unknown"));
    }

    private void showError(String message) {
        imageView.setVisibility(ImageView.GONE);
        textView.setText(message);
    }

    @Nullable
    private String guessMimeType(Uri uri) {
        String ext = null;
        String path = uri.getPath();
        if (path != null) {
            int dot = path.lastIndexOf('.');
            if (dot >= 0 && dot < path.length() - 1) {
                ext = path.substring(dot + 1).toLowerCase();
            }
        }
        if (ext == null) return null;
        return MimeTypeMap.getSingleton().getMimeTypeFromExtension(ext);
    }
}

